-- Rebuild baseline_rookies from rankings/*.csv (generated by scripts/build-baseline-migration-from-rankings.ts)
BEGIN;
DELETE FROM public.baseline_rookies WHERE league_type = 'dynasty' AND is_superflex = false AND scoring_format IN ('ppr', 'half_ppr', 'standard', 'any');
DELETE FROM public.baseline_rookies WHERE league_type = 'dynasty' AND is_superflex = true AND scoring_format IN ('ppr', 'half_ppr', 'standard', 'any');
COMMIT;